INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Sled_Overhead_Backward_Walk','Sled Overhead Backward Walk','hombros',ARRAY['pantorrillas','espalda media','cuádriceps'],'otro','strength',ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.','Face the sled, backing up until there is some tension in the line. Hold your hands directly above your head with your elbows extended. This will be your starting position.','Walk backwards, keeping your arms raised above your head. Avoid jerky movements.'],'Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight. Face the sled, backing up until there is some tension in the line. Hold your hands directly above your head with your elbows extended. This will be your starting position. Walk backwards, keeping your arms raised above your head. Avoid jerky movements.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Overhead_Backward_Walk/0.jpg','exercisedb',true),('Sled_Overhead_Triceps_Extension','Sled Overhead Triceps Extension','tríceps',ARRAY[]::text[],'otro','strength',ARRAY['Attach dual handles to a sled using a chain or rope. Load the sled to an appropriate load.','Facing away from the sled, step away until there is tension in the line. Raise your hands above your head, keeping them together, palms facing each other. Your elbows should be pointed upward with the elbows flexed. This will be your starting position.','Extend through the elbow to straighten the arm. Ensure that your upper arm stays in position to isolate the triceps.','Upon full extension, step forward to take the slack out of the line. You may keep your feet staggered for more stability.'],'Attach dual handles to a sled using a chain or rope. Load the sled to an appropriate load. Facing away from the sled, step away until there is tension in the line. Raise your hands above your head, keeping them together, palms facing each other. Your elbows should be pointed upward with the elbows flexed. This will be your starting position. Extend through the elbow to straighten the arm. Ensure that your upper arm stays in position to isolate the triceps. Upon full extension, step forward to take the slack out of the line. You may keep your feet staggered for more stability.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Overhead_Triceps_Extension/0.jpg','exercisedb',true),('Sled_Push','Sled Push','cuádriceps',ARRAY['pantorrillas','pecho','glúteos','isquiotibiales','tríceps'],'otro','strongman',ARRAY['Load your pushing sled with the desired weight.','Take an athletic posture, leaning into the sled with your arms fully extended, grasping the handles. Push the sled as fast as possible, focusing on extending your hips and knees to strengthen your posterior chain.'],'Load your pushing sled with the desired weight. Take an athletic posture, leaning into the sled with your arms fully extended, grasping the handles. Push the sled as fast as possible, focusing on extending your hips and knees to strengthen your posterior chain.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Push/0.jpg','exercisedb',true),('Sled_Reverse_Flye','Sled Reverse Flye','hombros',ARRAY[]::text[],'otro','strength',ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.','Face the sled, backing up until there is some tension in the line. Take both handles at arms length at about waist level. Bend the knees slightly and keep your chest and head up. This will be your starting position.','Without flexing the elbow, pull the handles upward and apart, performing a reverse fly with some external rotation. Your palms should be facing forward as you do this.','Return to the starting position, taking a couple steps back to take the slack out of the line.'],'Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight. Face the sled, backing up until there is some tension in the line. Take both handles at arms length at about waist level. Bend the knees slightly and keep your chest and head up. This will be your starting position. Without flexing the elbow, pull the handles upward and apart, performing a reverse fly with some external rotation. Your palms should be facing forward as you do this. Return to the starting position, taking a couple steps back to take the slack out of the line.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Reverse_Flye/0.jpg','exercisedb',true),('Sled_Row','Sled Row','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to an appropriate weight. Face the sled, backing up until there is some tension in the line.','With a handle in each hand, bend the knees slightly, keep your head and chest up, and begin with your arms extended.','To initiate the movement, flex the elbow as you retract your shoulder blades, pulling the sled towards you.','Take a step or two back to get tension in the line and repeat.'],'Attach dual handles to a sled connected by a rope or chain. Load the sled to an appropriate weight. Face the sled, backing up until there is some tension in the line. With a handle in each hand, bend the knees slightly, keep your head and chest up, and begin with your arms extended. To initiate the movement, flex the elbow as you retract your shoulder blades, pulling the sled towards you. Take a step or two back to get tension in the line and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sled_Row/0.jpg','exercisedb',true),('Sledgehammer_Swings','Sledgehammer Swings','abdominales',ARRAY['pantorrillas','antebrazos','dorsales','espalda media','hombros'],'otro','plyometrics',ARRAY['You will need a tire and a sledgehammer for this exercise. Stand in front of the tire about two feet away from it with a staggered stance. Grip the sledgehammer.','If you are right handed, your left hand should be at the bottom of the handle, and your right hand should be choking up closer to the head.','As you bring the sledge up, your right hand slides toward the head; as you swing down, your right hand will slide down to join your left hand. Slam it down as hard as you can against the tire. Control the bounce of the hammer off of the tire.','Repeat on the other side.'],'You will need a tire and a sledgehammer for this exercise. Stand in front of the tire about two feet away from it with a staggered stance. Grip the sledgehammer. If you are right handed, your left hand should be at the bottom of the handle, and your right hand should be choking up closer to the head. As you bring the sledge up, your right hand slides toward the head; as you swing down, your right hand will slide down to join your left hand. Slam it down as hard as you can against the tire. Control the bounce of the hammer off of the tire. Repeat on the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sledgehammer_Swings/0.jpg','exercisedb',true),('Smith_Incline_Shoulder_Raise','Smith Incline Shoulder Raise','hombros',ARRAY['pecho'],'barra','strength',ARRAY['Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your shoulders are aligned right under the barbell.','Using a shoulder width pronated (palms forward) grip, lift the bar from the rack and hold it straight over you with a slight bend at the elbows. This will be your starting position.','As you breathe out, lift the bar up until your arms are fully extended. Note: The contraction should be felt around the shoulders.','After a second pause, bring the bar back down to the starting position as you breathe in.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'],'Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your shoulders are aligned right under the barbell. Using a shoulder width pronated (palms forward) grip, lift the bar from the rack and hold it straight over you with a slight bend at the elbows. This will be your starting position. As you breathe out, lift the bar up until your arms are fully extended. Note: The contraction should be felt around the shoulders. After a second pause, bring the bar back down to the starting position as you breathe in. Repeat the movement for the prescribed amount of repetitions. When you are done, place the bar back in the rack.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Incline_Shoulder_Raise/0.jpg','exercisedb',true),('Smith_Machine_Behind_the_Back_Shrug','Smith Machine Behind the Back Shrug','trapecios',ARRAY['hombros'],'máquina','strength',ARRAY['With the bar at thigh level, load an appropriate weight.','Stand with the bar behind you, taking a shoulder-width, pronated grip on the bar and unhook the weight. You should be standing up straight with your head and chest up and your arms extended. This will be your starting position.','Initiate the movement by shrugging your shoulders straight up. Do not flex the arms or wrist during the movement.','After a brief pause return the weight to the starting position.','Repeat for the desired number of repetitions before engaging the hooks to rack the weight.'],'With the bar at thigh level, load an appropriate weight. Stand with the bar behind you, taking a shoulder-width, pronated grip on the bar and unhook the weight. You should be standing up straight with your head and chest up and your arms extended. This will be your starting position. Initiate the movement by shrugging your shoulders straight up. Do not flex the arms or wrist during the movement. After a brief pause return the weight to the starting position. Repeat for the desired number of repetitions before engaging the hooks to rack the weight.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Behind_the_Back_Shrug/0.jpg','exercisedb',true),('Smith_Machine_Bench_Press','Smith Machine Bench Press','pecho',ARRAY['hombros','tríceps'],'máquina','strength',ARRAY['Place a flat bench underneath the smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, lock the bar back in the rack.'],'Place a flat bench underneath the smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position. As you breathe in, come down slowly until you feel the bar on your middle chest. After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up. Repeat the movement for the prescribed amount of repetitions. When you are done, lock the bar back in the rack.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Bench_Press/0.jpg','exercisedb',true),('Smith_Machine_Bent_Over_Row','Smith Machine Bent Over Row','espalda media',ARRAY['bíceps','dorsales','hombros'],'máquina','strength',ARRAY['Set the barbell attached to the smith machine to a height that is about 2 inches below your knees.','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up.','Now grasp the barbell using an overhand (pronated) grip and unlock it from the smith machine rack. Then let it hang directly in front of you as your arms hang extended perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'Set the barbell attached to the smith machine to a height that is about 2 inches below your knees. Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. Now grasp the barbell using an overhand (pronated) grip and unlock it from the smith machine rack. Then let it hang directly in front of you as your arms hang extended perpendicular to the floor and your torso. This is your starting position. While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second. Slowly lower the weight again to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Bent_Over_Row/0.jpg','exercisedb',true);